void VAccvgprReadVop3p::execute_impl(amdgpu::Wavefront &wf) {
  uint64_t exec = wf.exec();
  for (uint32_t lane = 0; lane < wf.wf_size(); ++lane) {
    if (!(exec & (1ULL << lane)))
      continue;
    vdst.write_lane(wf, lane, src0.read_lane(wf, lane));
  }
}

